import sqlite3
from pathlib import Path

ROOT = Path(__file__).resolve().parents[1]


def expand_sql(relative_path):
    path = (ROOT / relative_path).resolve()
    if path == ROOT or ROOT not in path.parents:
        raise ValueError("SQL path escapes case repository")
    expanded = []
    for line in path.read_text(encoding="utf-8").splitlines():
        parts = line.strip().split(maxsplit=1)
        if parts and parts[0] == ".bail":
            continue
        if parts and parts[0] == ".read":
            if len(parts) != 2:
                raise ValueError("missing .read target")
            expanded.append(expand_sql(parts[1]))
        else:
            expanded.append(line)
    return "\n".join(expanded)


def run_sql(script_name):
    connection = sqlite3.connect(":memory:")
    try:
        connection.executescript(expand_sql(f"tests/{script_name}"))
    finally:
        connection.close()


def test_feedback_sql():
    run_sql("feedback.sql")
